// --- favorites-screen screen template (V35) ---
// 只保存从 index.html 拆出的静态 HTML；不写业务逻辑。
(function registerTemplate(global) {
    const registry = global.OwoApp && global.OwoApp.app && global.OwoApp.app.screenTemplates;
    if (!registry || typeof registry.registerTemplate !== 'function') {
        throw new Error('[favorites-screen template] OwoApp.app.screenTemplates 尚未初始化');
    }

    registry.registerTemplate('favorites-screen', "\n            <header class=\"app-header\">\n                <button class=\"back-btn\" data-target=\"more-screen\">‹</button>\n                <div class=\"title-container\">\n                    <h1 class=\"title\">收藏</h1>\n                </div>\n                <div class=\"placeholder favorites-header-actions\">\n                    <button type=\"button\" class=\"icon-btn favorites-delete-btn\" id=\"favorites-delete-btn\" title=\"多选删除\" aria-label=\"多选删除\">\n                        <svg viewBox=\"0 0 24 24\" width=\"22\" height=\"22\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><polyline points=\"3 6 5 6 21 6\"></polyline><path d=\"M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2\"></path><line x1=\"10\" y1=\"11\" x2=\"10\" y2=\"17\"></line><line x1=\"14\" y1=\"11\" x2=\"14\" y2=\"17\"></line></svg>\n                    </button>\n                </div>\n            </header>\n            <div class=\"favorites-tabs\">\n                <button type=\"button\" class=\"favorites-tab active\" data-filter=\"user\">我的收藏</button>\n                <button type=\"button\" class=\"favorites-tab\" data-filter=\"character\">角色收藏</button>\n            </div>\n            <main class=\"content favorites-content\">\n                <div id=\"favorites-list-container\" class=\"favorites-list-container\">\n                    <!-- 按角色/群聊分组的收藏卡片由 JS 渲染 -->\n                </div>\n                <div class=\"favorites-empty-placeholder\" id=\"favorites-empty-placeholder\" style=\"display: none;\">\n                    <div class=\"favorites-empty-icon\">☆</div>\n                    <p id=\"favorites-empty-text\">还没有收藏任何消息</p>\n                    <p class=\"favorites-empty-hint\" id=\"favorites-empty-hint\">在聊天中长按消息，选择「收藏」或「多选收藏」即可添加</p>\n                </div>\n            </main>\n            <!-- 收藏多选操作栏 -->\n            <div id=\"favorites-multi-select-bar\" class=\"favorites-multi-select-bar\" style=\"display: none;\">\n                <span id=\"favorites-select-count\">已选 0 项</span>\n                <div class=\"favorites-multi-select-actions\">\n                    <button type=\"button\" class=\"btn btn-neutral btn-small\" id=\"favorites-select-all-btn\">全选</button>\n                    <button type=\"button\" class=\"btn btn-danger btn-small\" id=\"favorites-batch-delete-btn\">删除已选</button>\n                    <button type=\"button\" class=\"btn btn-neutral btn-small\" id=\"favorites-multi-select-cancel-btn\">取消</button>\n                </div>\n            </div>\n        ", {
        owner: 'features/favorites',
        version: 'V35'
    });
})(window);
